fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let max_index = n - 1;
    let mut sieve = vec![true; max_index + 1];
    sieve[0] = false;
    sieve[1] = false;

    for i in 2..=max_index {
        if sieve[i] {
            let mut j = i * i;
            while j <= max_index {
                sieve[j] = false;
                j += i;
            }
        }
    }

    let mut sum_a = 0;
    let mut sum_b = 0;

    for (i, &num) in nums.iter().enumerate() {
        if sieve[i] {
            sum_a += num;
        } else {
            sum_b += num;
        }
    }

    (sum_a - sum_b).abs()
}
